import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { DocumentJob } from '../../data/models';

@Component({
  selector: 'app-documents',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './documents.component.html',
  styleUrl: './documents.component.css',
})
export class DocumentsComponent {
  readonly tabs = ['queue', 'review'];
  activeTab = signal('queue');
  selectedId = signal<string | null>(null);

  queuedCount = computed(() => this.seed.documents().filter((d) => d.status === 'queued').length);
  reviewCount = computed(() => this.seed.documents().filter((d) => d.status === 'review').length);
  confirmedCount = computed(() => this.seed.documents().filter((d) => d.status === 'confirmed').length);

  selectedDoc = computed<DocumentJob | undefined>(() => {
    const id = this.selectedId();
    if (id) return this.seed.documents().find((d) => d.id === id);
    return this.seed.documents().find((d) => d.status === 'review');
  });

  statusBadge(status: DocumentJob['status']): string {
    switch (status) {
      case 'queued': return 'badge-neutral';
      case 'extracting': return 'badge-info';
      case 'review': return 'badge-warning';
      case 'confirmed': return 'badge-success';
      default: return 'badge-neutral';
    }
  }

  typeBadge(type: DocumentJob['type']): string {
    switch (type) {
      case 'PO': return 'badge-info';
      case 'Spec': return 'badge-neutral';
      case 'Drawing': return 'badge-neutral';
      case 'RMA': return 'badge-warning';
      default: return 'badge-neutral';
    }
  }

  confidencePct(conf: number): number {
    return Math.round(conf * 100);
  }

  confidenceBadge(conf: number): string {
    if (conf >= 0.9) return 'badge-success';
    if (conf >= 0.8) return 'badge-warning';
    return 'badge-danger';
  }

  setTab(tab: string): void {
    this.router.navigate([], { queryParams: { tab }, queryParamsHandling: 'merge' });
  }

  review(id: string): void {
    this.router.navigate([], { queryParams: { tab: 'review', panel: id }, queryParamsHandling: 'merge' });
  }

  noop(): void { /* mockup no-op */ }

  constructor(public seed: SeedService, private route: ActivatedRoute, private router: Router) {
    this.route.queryParamMap.subscribe((q) => {
      const t = q.get('tab');
      this.activeTab.set(t && this.tabs.includes(t) ? t : 'queue');
      this.selectedId.set(q.get('panel'));
    });
  }
}
